# Opt in to the Local Zone (one-time, per account)
resource "aws_ec2_availability_zone_group" "lax" {
  group_name    = "us-west-2-lax-1"
  opt_in_status = "opted-in"
}

resource "aws_subnet" "lax" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.128.0/24"
  availability_zone = "us-west-2-lax-1a"

  # Must wait for opt-in before creating subnet
  depends_on = [aws_ec2_availability_zone_group.lax]

  tags = {
    Name = "lax-local-zone-subnet"
  }
}

resource "aws_instance" "lax_app" {
  ami           = data.aws_ami.amazon_linux.id
  instance_type = "c5.large"
  subnet_id     = aws_subnet.lax.id

  # Not all instance types are available in every Local Zone —
  # check availability before applying:
  # aws ec2 describe-instance-type-offerings --location-type availability-zone --filters
  # Name=location,Values=us-west-2-lax-1a

  tags = {
    Name = "lax-app-server"
  }
}
